import{_ as t,a}from"./chunks/频繁报错提示.B4wBXruJ.js";import{_ as i,o,c as s,a2 as l}from"./chunks/framework.DnrXFDHb.js";const b=JSON.parse('{"title":"User Rate Limits","description":"","frontmatter":{},"headers":[],"relativePath":"en/Safety/user-rate-limits.md","filePath":"en/Safety/user-rate-limits.md","lastUpdated":1781962217000}'),r={name:"en/Safety/user-rate-limits.md"};function d(n,e,p,h,u,c){return o(),s("div",null,[...e[0]||(e[0]=[l('<h1 id="user-rate-limits" tabindex="-1">User Rate Limits <a class="header-anchor" href="#user-rate-limits" aria-label="Permalink to &quot;User Rate Limits&quot;">​</a></h1><p>User rate limits control how often regular users or visitors can upload files from the homepage. This helps prevent public upload pages from being abused.</p><p>This feature only affects homepage uploads. Admin uploads and uploads made with API Tokens are not limited by user rate limits.</p><h2 id="where-to-configure-it" tabindex="-1">Where To Configure It <a class="header-anchor" href="#where-to-configure-it" aria-label="Permalink to &quot;Where To Configure It&quot;">​</a></h2><p>Open the admin panel, then go to:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Security Settings -&gt; Upload Management -&gt; User Rate Limits</span></span></code></pre></div><p><img src="'+t+'" alt="User rate limit settings" loading="lazy"></p><h2 id="enabling-rate-limits" tabindex="-1">Enabling Rate Limits <a class="header-anchor" href="#enabling-rate-limits" aria-label="Permalink to &quot;Enabling Rate Limits&quot;">​</a></h2><p>After <code>Enable Rate Limits</code> is turned on, ImgBed tracks recent uploads by uploader IP address.</p><p>Default values:</p><table tabindex="0"><thead><tr><th>Setting</th><th>Default</th><th>Description</th></tr></thead><tbody><tr><td>Detection window</td><td>1.5 hours</td><td>How far back upload records are counted.</td></tr><tr><td>Max file count</td><td>20</td><td>Maximum number of files allowed in the detection window.</td></tr><tr><td>Single file size limit</td><td>20 MB</td><td>Maximum size of one file.</td></tr><tr><td>Total upload size limit</td><td>200 MB</td><td>Maximum total upload size in the detection window.</td></tr></tbody></table><p>For example, with a 1.5 hour window, 20 files, 20 MB per file, and 200 MB total, uploads from the same IP are blocked once any configured limit is exceeded.</p><h2 id="excluding-file-types" tabindex="-1">Excluding File Types <a class="header-anchor" href="#excluding-file-types" aria-label="Permalink to &quot;Excluding File Types&quot;">​</a></h2><p><code>Excluded upload file types</code> blocks regular users or visitors from uploading selected file categories.</p><p>Available categories:</p><table tabindex="0"><thead><tr><th>Type</th><th>Description</th></tr></thead><tbody><tr><td>Images</td><td>jpg, png, webp, gif, and similar image files</td></tr><tr><td>Videos</td><td>mp4, webm, mov, and similar video files</td></tr><tr><td>Audio</td><td>mp3, flac, wav, and similar audio files</td></tr><tr><td>Documents</td><td>pdf, txt, md, docx, and similar document files</td></tr><tr><td>Other</td><td>Files outside the above categories, such as zip, rar, exe, apk</td></tr></tbody></table><p>By default, a type is not selected, which means it is allowed.</p><p>Clicking a type highlights it, which means that type is blocked.</p><p>If <code>Other</code> is selected, visitors uploading zip or rar files will be blocked and told that this file type is not supported.</p><h2 id="block-messages" tabindex="-1">Block Messages <a class="header-anchor" href="#block-messages" aria-label="Permalink to &quot;Block Messages&quot;">​</a></h2><p>When a limit is triggered, users see a matching message:</p><p><img src="'+a+'" alt="Too frequent upload message" loading="lazy"></p><table tabindex="0"><thead><tr><th>Scenario</th><th>Message Meaning</th></tr></thead><tbody><tr><td>Single file too large</td><td>The file is too large and should be compressed before upload.</td></tr><tr><td>File type blocked</td><td>This file type is not supported. Remove it and try again.</td></tr><tr><td>Uploads too frequent</td><td>Recent uploads are too frequent, with a retry time shown.</td></tr><tr><td>Total size too high</td><td>Recent total upload size is too high, with a retry time shown.</td></tr></tbody></table><h2 id="when-to-enable-it" tabindex="-1">When To Enable It <a class="header-anchor" href="#when-to-enable-it" aria-label="Permalink to &quot;When To Enable It&quot;">​</a></h2><p>Enable user rate limits if your upload homepage is publicly accessible.</p><p>Common reasons:</p><ul><li>You are worried about scripted bulk uploads.</li><li>You want to limit large visitor uploads.</li><li>You only want regular users to upload images, not archives or installers.</li><li>You want to keep public upload available while controlling resource usage.</li></ul><p>If the site is only for yourself, or only administrators can upload, you can leave this disabled.</p>',28)])])}const f=i(r,[["render",d]]);export{b as __pageData,f as default};
